	test("serialize and equal") {
		val sudoku = Sudoku.deserialize(board)
		val sukaku = Sukaku.deserialize(board)
		assert(sudoku.isConsistent())
		assert(sukaku.isConsistent())

		assertEquals(sukaku.board(0)(4).number(), Some(SudokuInt(8)))
		assertEquals(sukaku.board(1)(3).number(), Some(SudokuInt(5)))
		assertEquals(sukaku.board(1)(5).number(), Some(SudokuInt(2)))
		assertEquals(sukaku.board(2)(2).number(), Some(SudokuInt(3)))
		assertEquals(sukaku.board(2)(6).number(), Some(SudokuInt(1)))
		assertEquals(sukaku.board(3)(1).number(), Some(SudokuInt(5)))
		assertEquals(sukaku.board(3)(7).number(), Some(SudokuInt(2)))
		assertEquals(sukaku.board(4)(0).number(), Some(SudokuInt(8)))
		assertEquals(sukaku.board(4)(4).number(), Some(SudokuInt(9)))
		assertEquals(sukaku.board(4)(8).number(), Some(SudokuInt(6)))
		assertEquals(sukaku.board(5)(0).number(), Some(SudokuInt(6)))
		assertEquals(sukaku.board(5)(3).number(), Some(SudokuInt(3)))
		assertEquals(sukaku.board(5)(4).number(), Some(SudokuInt(7)))
		assertEquals(sukaku.board(5)(5).number(), Some(SudokuInt(5)))
		assertEquals(sukaku.board(5)(8).number(), Some(SudokuInt(9)))
		assertEquals(sukaku.board(6)(1).number(), Some(SudokuInt(1)))
		assertEquals(sukaku.board(6)(2).number(), Some(SudokuInt(5)))
		assertEquals(sukaku.board(6)(4).number(), Some(SudokuInt(2)))
		assertEquals(sukaku.board(6)(6).number(), Some(SudokuInt(8)))
		assertEquals(sukaku.board(6)(7).number(), Some(SudokuInt(3)))
		assertEquals(sukaku.board(7)(4).number(), Some(SudokuInt(5)))
		assertEquals(sukaku.board(8)(3).number(), Some(SudokuInt(7)))
		assertEquals(sukaku.board(8)(4).number(), Some(SudokuInt(3)))
		assertEquals(sukaku.board(8)(5).number(), Some(SudokuInt(9)))

		assertEquals(sukaku.serialize(), board)

		assert(sukaku == sudoku)

		assert(sudoku == Sudoku.fromString(sudoku.toString()))
	}

	test("fill and consistent") {
		var sudoku = Sukaku.deserialize(board)
		sudoku = sudoku.fillNumber(0, 0, 1)
		assert(sudoku.board(0)(0).number() == Some(SudokuInt(1)))
		assert(sudoku.isConsistent())
		assert(Sudoku(sudoku.board).isConsistent())
		sudoku = sudoku.fillNumber(1, 1, 2)
		assert(!sudoku.isConsistent())
	}

	test("DLX solve") {
		val sudoku = Sukaku.deserialize(board)
		val result = DLXSolver.solve(sudoku)
		assertMatches(result) {
			case DLXSolver.State.Solved(solution) => solution == Sukaku.deserialize(solved)
			case _ => false
		}
		val multiResult = DLXSolver.solve(Sukaku.deserialize(multi))
		assertEquals(multiResult, DLXSolver.State.MultiSolution)
	}

	test("puzzle generation") {
		val puzzle = SudokuGenerator().generate()
		assert(puzzle.isConsistent())
		assert(DLXSolver.solve(puzzle).isInstanceOf[DLXSolver.State.Solved])
	}

